import{j as e}from"./index-CJfhJpqD.js";import{P as a,a as o}from"./PageShell-BQnP8yY3.js";import{s}from"./soberano-hd-zD9uOcpd.js";import"./Footer-C8dOssaH.js";function d(){return e.jsx(a,{eyebrow:"A Origem da Maçonaria",title:e.jsxs(e.Fragment,{children:["Das corporações obreiras",e.jsx("br",{}),e.jsx("span",{className:"text-gradient-gold italic",children:"à maçonaria especulativa"})]}),backgroundImage:s,children:e.jsxs(o,{children:[e.jsx("p",{children:"Sobre as origens da Maçonaria, têm-se gasto rios de tinta e escrito as mais fantasiosas histórias. Desde os mistérios de Elêusis ao rei Salomão e à Ordem do Templo, tudo tem servido a maçons, desejosos de exaltar a antiguidade da Ordem, e a profanos não menos desejosos de denegrir essa mesma Ordem."}),e.jsxs("p",{children:["Ligação direta com o passado, só a encontramos no que respeita ao corporativismo obreiro. Como diz o historiador Paul Naudon: ",e.jsx("em",{children:'"a franco-maçonaria apresenta-se como a continuação e a transformação da organização dos mestres da Idade Média e do Renascimento, na qual o elemento especulativo tomou o lugar do elemento operativo"'}),"."]}),e.jsx("h3",{children:"As corporações dos mestres"}),e.jsx("p",{children:"As corporações dos mestres conheciam, para além do seu caráter puramente profissional, preocupações de outra natureza: religiosa, iniciática, caritativa, cultural. Tinham seus patronos próprios, suas festas rituais — muitas vezes remontando à Antiguidade —, seus mistérios e sua intensa solidariedade."}),e.jsxs("p",{children:["A corporação dos pedreiros, ligada à nobre arte da arquitetura, incluía-se entre as mais importantes e ricas em simbologia. Nela se fundiam princípios e tradições de construção que remontavam aos ",e.jsx("strong",{children:"Egípcios, Hebreus, Caldeus, Fenícios, Gregos, Romanos e Bizantinos"})," — em suma, a todo o corpus da civilização europeia."]}),e.jsx("h3",{children:"A influência templária"}),e.jsx("p",{children:"Não deixa de impressionar a existência de elementos que lembram a organização das ordens da cavalaria e, sobretudo, o ideário dos Templários. Grande parte do vocabulário maçônico está ligada ao judaísmo bíblico. Parece, todavia, que esta associação se deve mais à influência que os Templários exerceram na construção civil e religiosa do que a uma ligação direta entre a Ordem do Templo e a Ordem Maçônica."}),e.jsx("h3",{children:"A passagem ao especulativo"}),e.jsx("p",{children:'Já desde o século XV, as corporações maçônicas escocesas tinham impetrado do rei o privilégio de terem à sua frente, como "grande mestre", um nobre de boa linhagem, hereditário. No século XVII, muitas lojas britânicas foram reorganizadas segundo o modelo das academias italianas.'}),e.jsxs("p",{children:["Estes maçons aceitos tornaram-se, com o andar dos tempos, tão numerosos que imprimiram à corporação um aspecto completamente diverso do anterior. Nas corporações onde tal começou a acontecer, ",e.jsx("strong",{children:"o elemento operativo foi cedendo o lugar ao elemento especulativo"}),"."]}),e.jsx("p",{children:"Uma transformação deste tipo levou centenas de anos a completar-se. E só na Grã-Bretanha, onde a tradição corporativa se manteve sem desfalecimento até o século XVIII, foi possível às antigas lojas de pedreiros operativos converterem-se, por completo, em lojas de pedreiros especulativos — mantendo o prestígio e o relevo social do passado, conservando o simbolismo e o ritual de tempos remotos."})]})})}export{d as component};
